    fun classify(merchantName: String): String? {
        val mClean = merchantName.uppercase(Locale.US).trim()
        
        // 1. Exact Match check
        merchantMap[mClean]?.let { return it }
        
        // 2. Substring/Contains check
        // Check if any key in our map is contained within the merchant name,
        // or if the merchant name contains any key.
        // We optimize by checking matches against a list of common keywords first.
        for ((key, value) in merchantMap) {
            if (key.length >= 3 && (mClean.contains(key) || key.contains(mClean))) {
                return value
            }
        }
        
        // 3. Regex / Keyword fallbacks if not matched in the dictionary
        return when {
            // Food
            mClean.contains("FOODPANDA") || mClean.contains("DOMINOS") || mClean.contains("PIZZA") || 
            mClean.contains("BURGER") || mClean.contains("REST") || mClean.contains("DINE") || 
            mClean.contains("KFC") || mClean.contains("BFC") || mClean.contains("CHILLOX") || 
            mClean.contains("MADCHEF") || mClean.contains("TAKEOUT") || mClean.contains("SULTAN") ||
            mClean.contains("KACCHI") || mClean.contains("CAFE") || mClean.contains("SWEET") || 
            mClean.contains("CATER") || mClean.contains("BAKE") -> "Food & Dining"
            
            // Groceries
            mClean.contains("SHWAPNO") || mClean.contains("UNIMART") || mClean.contains("AGORA") || 
            mClean.contains("MEENA") || mClean.contains("GROCERY") || mClean.contains("SUPER") || 
            mClean.contains("CHALDAL") || mClean.contains("PANDAMART") -> "Groceries"
            
            // Transport
            mClean.contains("UBER") || mClean.contains("PATHAO") || mClean.contains("SHOHOZ") || 
            mClean.contains("TRAIN") || mClean.contains("RAILWAY") || mClean.contains("FLIGHT") ||
            mClean.contains("BIMAN") || mClean.contains("AIRWAYS") || mClean.contains("CAR") || 
            mClean.contains("METRO") || mClean.contains("RIDE") || mClean.contains("PARIBAHAN") -> "Transportation"
            
            // Shopping
            mClean.contains("DARAZ") || mClean.contains("AMAZON") || mClean.contains("ALIEXPRESS") || 
            mClean.contains("SHEBA") || mClean.contains("SHOP") || mClean.contains("PAYPAL") || 
            mClean.contains("E-COM") || mClean.contains("GIFT") || mClean.contains("AARONG") || 
            mClean.contains("YELLOW") || mClean.contains("APEX") || mClean.contains("BATA") || 
            mClean.contains("WALTON") || mClean.contains("SINGER") || mClean.contains("RANGS") || 
            mClean.contains("TRANSCOM") || mClean.contains("COMPUTERS") || mClean.contains("TECH") -> "Shopping"
            
            // Utilities
            mClean.contains("DESCO") || mClean.contains("WASA") || mClean.contains("DPDC") || 
            mClean.contains("BTCL") || mClean.contains("BILL") || mClean.contains("UTILITY") || 
            mClean.contains("INTERNET") || mClean.contains("BROADBAND") || mClean.contains("RECHARGE") -> "Utilities"

            // Travel & Lodging
            mClean.contains("HOTEL") || mClean.contains("RESORT") || mClean.contains("TRAVEL") || 
            mClean.contains("TOUR") || mClean.contains("VACATION") || mClean.contains("LODGE") || 
            mClean.contains("TRIP") || mClean.contains("GAYAAN") -> "Travel & Lodging"

            // Entertainment
            mClean.contains("NETFLIX") || mClean.contains("SPOTIFY") || mClean.contains("CINEPLEX") || 
            mClean.contains("CINEMA") || mClean.contains("THEATRE") || mClean.contains("PRIME VIDEO") || 
            mClean.contains("YOUTUBE") || mClean.contains("PLAYSTATION") || mClean.contains("STEAM") -> "Entertainment & Subscriptions"

            // Health & Education
            mClean.contains("HOSPITAL") || mClean.contains("DIAGNOSTIC") || mClean.contains("CLINIC") || 
            mClean.contains("PHARMA") || mClean.contains("DRUG") || mClean.contains("HEALTH") || 
            mClean.contains("LAB") || mClean.contains("UNIVERSITY") || mClean.contains("SCHOOL") || 
            mClean.contains("TUITION") || mClean.contains("COLLEGE") || mClean.contains("ACADEMY") -> "Health & Education"
            
            else -> null
        }
    }
